<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Kanban Board</title>
<style>
  * { box-sizing: border-box; }
  body {
    margin: 0;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    background: linear-gradient(135deg, #eef2f7 0%, #e3eaf3 100%);
    color: #1f2937;
    min-height: 100vh;
    padding: 32px 20px;
  }
  h1 {
    margin: 0 0 24px;
    text-align: center;
    font-size: 28px;
    font-weight: 700;
    letter-spacing: -0.5px;
    color: #111827;
  }
  .controls {
    max-width: 980px;
    margin: 0 auto 28px;
    display: flex;
    gap: 10px;
    justify-content: center;
  }
  #new-card {
    flex: 1;
    max-width: 420px;
    padding: 12px 16px;
    font-size: 15px;
    border: 1px solid #d1d5db;
    border-radius: 10px;
    outline: none;
    transition: border-color .15s, box-shadow .15s;
  }
  #new-card:focus {
    border-color: #6366f1;
    box-shadow: 0 0 0 3px rgba(99,102,241,.15);
  }
  #add-card {
    padding: 12px 22px;
    font-size: 15px;
    font-weight: 600;
    color: #fff;
    background: #6366f1;
    border: none;
    border-radius: 10px;
    cursor: pointer;
    transition: background .15s, transform .05s;
  }
  #add-card:hover { background: #4f46e5; }
  #add-card:active { transform: translateY(1px); }

  .board {
    max-width: 980px;
    margin: 0 auto;
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 20px;
  }
  .column {
    background: #ffffff;
    border-radius: 14px;
    box-shadow: 0 1px 3px rgba(15,23,42,.06), 0 8px 24px rgba(15,23,42,.04);
    display: flex;
    flex-direction: column;
    overflow: hidden;
    border: 1px solid #e5e7eb;
  }
  .column.drag-over {
    box-shadow: 0 0 0 2px #6366f1, 0 8px 24px rgba(99,102,241,.18);
    background: #fafbff;
  }
  .col-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 16px 18px;
    border-bottom: 1px solid #eef0f4;
    background: #fafbfc;
  }
  .col-title {
    font-size: 14px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: .6px;
    color: #374151;
  }
  .count {
    background: #eef2ff;
    color: #4338ca;
    font-size: 13px;
    font-weight: 700;
    min-width: 24px;
    height: 24px;
    padding: 0 8px;
    border-radius: 12px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
  }
  .card-container {
    padding: 14px;
    display: flex;
    flex-direction: column;
    gap: 10px;
    min-height: 120px;
    flex: 1;
  }
  .card {
    background: #fff;
    border: 1px solid #e5e7eb;
    border-radius: 10px;
    padding: 12px 14px;
    box-shadow: 0 1px 2px rgba(15,23,42,.05);
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 10px;
    cursor: grab;
    transition: box-shadow .15s, transform .05s, border-color .15s;
    word-break: break-word;
  }
  .card:hover {
    box-shadow: 0 4px 12px rgba(15,23,42,.08);
    border-color: #d1d5db;
  }
  .card.dragging {
    opacity: .5;
    cursor: grabbing;
  }
  .card-text {
    font-size: 14px;
    line-height: 1.4;
    color: #1f2937;
    flex: 1;
  }
  .card-del {
    background: transparent;
    border: none;
    color: #9ca3af;
    font-size: 16px;
    line-height: 1;
    cursor: pointer;
    padding: 2px 6px;
    border-radius: 6px;
    transition: background .15s, color .15s;
    flex-shrink: 0;
  }
  .card-del:hover {
    background: #fee2e2;
    color: #dc2626;
  }
  .empty-hint {
    text-align: center;
    color: #9ca3af;
    font-size: 13px;
    padding: 18px 0;
    font-style: italic;
  }
  @media (max-width: 720px) {
    .board { grid-template-columns: 1fr; }
  }
</style>
</head>
<body>
  <h1>Kanban Board</h1>
  <div class="controls">
    <input id="new-card" type="text" placeholder="Enter a task and press Add..." />
    <button id="add-card">Add</button>
  </div>

  <div class="board">
    <section id="col-todo" class="column">
      <div class="col-header">
        <span class="col-title">To Do</span>
        <span class="count">0</span>
      </div>
      <div class="card-container"></div>
    </section>
    <section id="col-doing" class="column">
      <div class="col-header">
        <span class="col-title">Doing</span>
        <span class="count">0</span>
      </div>
      <div class="card-container"></div>
    </section>
    <section id="col-done" class="column">
      <div class="col-header">
        <span class="col-title">Done</span>
        <span class="count">0</span>
      </div>
      <div class="card-container"></div>
    </section>
  </div>

<script>
(function () {
  "use strict";

  var STORAGE_KEY = "kanban-state-v1";
  var columns = ["col-todo", "col-doing", "col-done"];
  var draggingId = null;

  function loadState() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return { todo: [], doing: [], done: [] };
      var parsed = JSON.parse(raw);
      return {
        todo: Array.isArray(parsed.todo) ? parsed.todo : [],
        doing: Array.isArray(parsed.doing) ? parsed.doing : [],
        done: Array.isArray(parsed.done) ? parsed.done : []
      };
    } catch (e) {
      return { todo: [], doing: [], done: [] };
    }
  }

  function saveState() {
    var state = readState();
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }

  function readState() {
    var state = { todo: [], doing: [], done: [] };
    columns.forEach(function (colId) {
      var col = document.getElementById(colId);
      var container = col.querySelector(".card-container");
      var cards = container.querySelectorAll(".card");
      cards.forEach(function (card) {
        state[colId.replace("col-", "")].push({
          id: card.getAttribute("data-id"),
          title: card.getAttribute("data-title")
        });
      });
    });
    return state;
  }

  function makeId() {
    return "c-" + Date.now().toString(36) + "-" + Math.random().toString(36).slice(2, 7);
  }

  function createCardElement(id, title) {
    var card = document.createElement("div");
    card.className = "card";
    card.setAttribute("draggable", "true");
    card.setAttribute("data-id", id);
    card.setAttribute("data-title", title);

    var text = document.createElement("span");
    text.className = "card-text";
    text.textContent = title;

    var del = document.createElement("button");
    del.className = "card-del";
    del.type = "button";
    del.setAttribute("aria-label", "Delete card");
    del.textContent = "✕";
    del.addEventListener("click", function () {
      card.remove();
      updateAllCounts();
      saveState();
    });

    card.appendChild(text);
    card.appendChild(del);

    card.addEventListener("dragstart", function (e) {
      draggingId = id;
      card.classList.add("dragging");
      e.dataTransfer.effectAllowed = "move";
      try {
        e.dataTransfer.setData("text/plain", id);
      } catch (err) {}
    });

    card.addEventListener("dragend", function () {
      card.classList.remove("dragging");
      draggingId = null;
      columns.forEach(function (cid) {
        document.getElementById(cid).classList.remove("drag-over");
      });
    });

    return card;
  }

  function findCardById(id) {
    return document.querySelector('.card[data-id="' + id + '"]');
  }

  function updateCount(colId) {
    var col = document.getElementById(colId);
    var container = col.querySelector(".card-container");
    var n = container.querySelectorAll(".card").length;
    col.querySelector(".count").textContent = String(n);
  }

  function updateAllCounts() {
    columns.forEach(updateCount);
  }

  function renderColumn(colId, items) {
    var col = document.getElementById(colId);
    var container = col.querySelector(".card-container");
    container.innerHTML = "";
    items.forEach(function (item) {
      container.appendChild(createCardElement(item.id, item.title));
    });
    updateCount(colId);
  }

  function renderAll() {
    var state = loadState();
    renderColumn("col-todo", state.todo);
    renderColumn("col-doing", state.doing);
    renderColumn("col-done", state.done);
  }

  function addCard() {
    var input = document.getElementById("new-card");
    var text = input.value.trim();
    if (!text) return;
    var id = makeId();
    var card = createCardElement(id, text);
    var container = document.getElementById("col-todo").querySelector(".card-container");
    container.appendChild(card);
    updateCount("col-todo");
    input.value = "";
    input.focus();
    saveState();
  }

  // Add button
  document.getElementById("add-card").addEventListener("click", addCard);
  // Enter key in input
  document.getElementById("new-card").addEventListener("keydown", function (e) {
    if (e.key === "Enter") {
      e.preventDefault();
      addCard();
    }
  });

  // Drag-and-drop on columns
  columns.forEach(function (colId) {
    var col = document.getElementById(colId);

    col.addEventListener("dragover", function (e) {
      e.preventDefault();
      e.dataTransfer.dropEffect = "move";
      col.classList.add("drag-over");
    });

    col.addEventListener("dragenter", function (e) {
      e.preventDefault();
      col.classList.add("drag-over");
    });

    col.addEventListener("dragleave", function (e) {
      // Only remove if leaving the column entirely
      if (!col.contains(e.relatedTarget)) {
        col.classList.remove("drag-over");
      }
    });

    col.addEventListener("drop", function (e) {
      e.preventDefault();
      col.classList.remove("drag-over");
      var id = draggingId;
      if (!id) {
        try { id = e.dataTransfer.getData("text/plain"); } catch (err) {}
      }
      if (!id) return;

      var card = findCardById(id);
      if (!card) return;

      // If already in this column, do nothing
      var container = col.querySelector(".card-container");
      if (container.contains(card)) {
        return;
      }

      // Insert at drop position if possible, else append
      var insertBefore = null;
      var afterEl = getCardAfterPoint(container, e.clientY);
      if (afterEl) {
        insertBefore = afterEl;
      }
      if (insertBefore) {
        container.insertBefore(card, insertBefore);
      } else {
        container.appendChild(card);
      }

      updateAllCounts();
      saveState();
    });
  });

  function getCardAfterPoint(container, y) {
    var cards = Array.prototype.slice.call(container.querySelectorAll(".card:not(.dragging)"));
    var closest = null;
    var closestOffset = Number.NEGATIVE_INFINITY;
    cards.forEach(function (card) {
      var rect = card.getBoundingClientRect();
      var offset = y - (rect.top + rect.height / 2);
      if (offset < 0 && offset > closestOffset) {
        closestOffset = offset;
        closest = card;
      }
    });
    return closest;
  }

  // Initial render
  renderAll();
})();
</script>
</body>
</html>
